#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define MAX_SESSIONS 100
#define SESSION_EXPIRY 300 // seconds

typedef struct {
    char session_id[256];
    char *data;
    time_t last_access;
    int active;
} Session;

typedef struct {
    Session sessions[MAX_SESSIONS];
} Cache;

void init_cache(Cache *cache) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        cache->sessions[i].data = NULL;
        cache->sessions[i].active = 0;
    }
}

int find_session(Cache *cache, const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (strcmp(cache->sessions[i].session_id, session_id) == 0) {
            return i;
        }
    }
    return -1;
}

void create_session(Cache *cache, const char *session_id, const char *data) {
    int index = find_session(cache, session_id);
    if (index == -1) {
        for (int i = 0; i < MAX_SESSIONS; i++) {
            if (!cache->sessions[i].active) {
                strcpy(cache->sessions[i].session_id, session_id);
                cache->sessions[i].data = strdup(data);
                cache->sessions[i].last_access = time(NULL);
                cache->sessions[i].active = 1;
                break;
            }
        }
    }
}

char *access_session(Cache *cache, const char *session_id) {
    int index = find_session(cache, session_id);
    if (index != -1) {
        time_t now = time(NULL);
        if (difftime(now, cache->sessions[index].last_access) < SESSION_EXPIRY) {
            cache->sessions[index].last_access = now;
            return cache->sessions[index].data;
        } else {
            free(cache->sessions[index].data);
            cache->sessions[index].data = NULL;
            cache->sessions[index].active = 0;
        }
    }
    return NULL;
}

void invalidate_session(Cache *cache, const char *session_id) {
    int index = find_session(cache, session_id);
    if (index != -1) {
        if (cache->sessions[index].data) {
            free(cache->sessions[index].data);
            cache->sessions[index].data = NULL;
        }
        cache->sessions[index].active = 0;
    }
}

void clear_expired_sessions(Cache *cache) {
    time_t now = time(NULL);
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache->sessions[i].active && difftime(now, cache->sessions[i].last_access) >= SESSION_EXPIRY) {
            free(cache->sessions[i].data);
            cache->sessions[i].data = NULL;
            cache->sessions[i].active = 0;
        }
    }
}

